<?php if(!defined('ABSPATH')){exit;}require_once AUTHME_PLUGIN_DIR.'config/mail-config.php';class AuthMe_Email{public function send_email($template_id,$to_email,$dynamic_data=array()){$config=authme_get_email_config($template_id);if(!$config){return false;}$subject=$config['subject'];ob_start();$tpl=AuthMe_Assets_Loader::dir('tpl_master_mail');if($tpl&&file_exists($tpl)){include $tpl;}else{echo wp_kses_post($config['message']);}$body=ob_get_clean();$headers=array('Content-Type: text/html; charset=UTF-8');return wp_mail($to_email,$subject,$body,$headers);}public function send_otp_email($to_email,$otp_code,$purpose='registration'){$template_id='registration_otp';if($purpose==='password_reset'){$template_id='password_reset_otp';}elseif($purpose==='host_request'){$template_id='host_request_otp';}return $this->send_email($template_id,$to_email,array('otp_code'=>$otp_code));}public function send_password_changed_email($to_email,$user_name){return $this->send_email('password_changed',$to_email);}public function send_host_approved_email($to_email,$username,$password){return $this->send_email('host_approved',$to_email,array('username'=>$username,'password'=>$password,));}public function send_host_rejected_email($to_email){return $this->send_email('host_rejected',$to_email);}public function send_admin_host_request_notification($user_data){$admin_email=get_option('admin_email');return $this->send_email('admin_host_request',$admin_email,array('all_details'=>$user_data,));}}